PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?dance ?danceLabel WHERE {
  wd:Q21852951 wdt:P155 ?season.
  ?season wdt:P1543 "14"^^xsd:integer.
  ?performance wdt:P1635 ?score.
  ?performance wdt:P1721 ?dance.
  ?dance wdt:P279+ wd:Q873185.
  FILTER(?score = 28)
  OPTIONAL { ?dance rdfs:label ?danceLabel. FILTER(LANG(?danceLabel) = 'en') }
}

